  const handleRewind = useCallback(async () => {
    if (userHistory.current.length === 0) {
      showAlert('No History', 'No previous profiles to rewind to', [{ text: 'OK', style: 'default' }], 'alert-circle');
      return;
    }
    if (!user?.premium?.isActive) {
      showAlert(
        'Premium Feature',
