  const handleSuperLike = useCallback(async () => {
    if (currentIndex >= users.length) return;
    const targetUser = users[currentIndex];

    // Check premium status before making API call
    if (!user?.premium?.isActive) {
      showAlert(
        'Premium Feature', 
